import os
import secrets
import imghdr
from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename
from PIL import Image
import io

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.getcwd(), 'uploads', 'profile_pictures')
MAX_FILE_SIZE = 5 * 1024 * 1024  # 5MB
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
MAX_IMAGE_DIMENSION = 4096  # Maximum width or height

# Create upload directory if it doesn't exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Set proper permissions on upload directory
os.chmod(UPLOAD_FOLDER, 0o755)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE


def validate_image_content(file_stream):
    """Validate that the file is actually an image by checking its content"""
    try:
        # Reset stream position
        file_stream.seek(0)
        
        # Use imghdr to detect actual image type from content
        image_type = imghdr.what(file_stream)
        
        if image_type not in ALLOWED_EXTENSIONS:
            return False, None
        
        # Reset stream position for PIL
        file_stream.seek(0)
        
        # Use PIL to validate and process the image
        img = Image.open(file_stream)
        
        # Verify image can be loaded (detects corrupted files)
        img.verify()
        
        # Reset stream and reload for further processing
        file_stream.seek(0)
        img = Image.open(file_stream)
        
        # Check image dimensions
        width, height = img.size
        if width > MAX_IMAGE_DIMENSION or height > MAX_IMAGE_DIMENSION:
            return False, None
        
        # Convert to RGB if necessary (removes potential exploits in other modes)
        if img.mode not in ('RGB', 'RGBA'):
            img = img.convert('RGB')
        
        return True, img
        
    except Exception as e:
        return False, None


def generate_secure_filename(original_filename):
    """Generate a secure random filename while preserving extension"""
    # Extract extension safely
    ext = original_filename.rsplit('.', 1)[1].lower() if '.' in original_filename else ''
    
    # Validate extension
    if ext not in ALLOWED_EXTENSIONS:
        return None
    
    # Generate random filename
    random_filename = secrets.token_urlsafe(16)
    return f"{random_filename}.{ext}"


@app.route('/upload-profile-picture', methods=['POST'])
def upload_profile_picture():
    """Secure endpoint for uploading profile pictures"""
    
    # Check if file is in request
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    # Check if filename is empty
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    # Validate file extension first
    if '.' not in file.filename:
        return jsonify({'error': 'Invalid file format'}), 400
    
    ext = file.filename.rsplit('.', 1)[1].lower()
    if ext not in ALLOWED_EXTENSIONS:
        return jsonify({'error': f'File type not allowed. Allowed types: {", ".join(ALLOWED_EXTENSIONS)}'}), 400
    
    # Read file content into memory (respects MAX_CONTENT_LENGTH)
    try:
        file_stream = io.BytesIO(file.read())
    except Exception as e:
        return jsonify({'error': 'File too large or read error'}), 413
    
    # Validate actual image content
    is_valid, img = validate_image_content(file_stream)
    
    if not is_valid:
        return jsonify({'error': 'Invalid or corrupted image file'}), 400
    
    # Generate secure filename
    secure_name = generate_secure_filename(file.filename)
    if not secure_name:
        return jsonify({'error': 'Invalid file extension'}), 400
    
    # Ensure filename doesn't contain path traversal
    secure_name = secure_filename(secure_name)
    
    # Create full path (ensure it's within upload directory)
    filepath = os.path.abspath(os.path.join(app.config['UPLOAD_FOLDER'], secure_name))
    
    # Verify the resolved path is still within upload folder (prevent path traversal)
    if not filepath.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
        return jsonify({'error': 'Invalid file path'}), 400
    
    # Save the validated and processed image
    try:
        # Save with PIL to strip metadata and re-encode safely
        img.save(filepath, format=ext.upper() if ext != 'jpg' else 'JPEG', quality=95)
        
        # Set restrictive permissions on uploaded file
        os.chmod(filepath, 0o644)
        
        return jsonify({
            'message': 'Profile picture uploaded successfully',
            'filename': secure_name,
            'url': f'/profile-pictures/{secure_name}'
        }), 201
        
    except Exception as e:
        # Clean up on error
        if os.path.exists(filepath):
            os.remove(filepath)
        return jsonify({'error': 'Failed to save file'}), 500


@app.route('/profile-pictures/<filename>', methods=['GET'])
def get_profile_picture(filename):
    """Serve uploaded profile pictures"""
    
    # Sanitize filename
    filename = secure_filename(filename)
    
    # Verify file exists and is within upload directory
    filepath = os.path.abspath(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    
    if not filepath.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
        return jsonify({'error': 'Invalid file path'}), 400
    
    if not os.path.exists(filepath):
        return jsonify({'error': 'File not found'}), 404
    
    # Serve file with appropriate headers
    return send_from_directory(
        app.config['UPLOAD_FOLDER'],
        filename,
        as_attachment=False,
        mimetype=f'image/{filename.rsplit(".", 1)[1].lower()}'
    )


@app.errorhandler(413)
def request_entity_too_large(error):
    """Handle file size limit exceeded"""
    return jsonify({'error': f'File too large. Maximum size is {MAX_FILE_SIZE / (1024*1024)}MB'}), 413


if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)